import{_ as i,o as e,c as a,a as n}from"./chunks/framework.8tiMeCK-.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_networking/ch06_7.md","filePath":"notes/linux_kernel_networking/ch06_7.md","lastUpdated":null}'),l={name:"notes/linux_kernel_networking/ch06_7.md"};function p(t,s,r,d,o,c){return e(),a("div",null,[...s[0]||(s[0]=[n(`<h3 id="_6-7-策略路由-policy-routing" tabindex="-1">6.7 策略路由（Policy Routing） <a class="header-anchor" href="#_6-7-策略路由-policy-routing" aria-label="Permalink to &quot;6.7  策略路由（Policy Routing）&quot;">​</a></h3><p>上一节我们聊了组播，那是关于「一对多」的艺术。这一节，我们要把视角拉回来，重新审视那个看似简单的动作——<strong>查表</strong>。</p><p>在传统的路由观念里，数据包就像一个只看目的地的旅客：不管你是谁、不管你从哪来、不管你背负着什么标记，只要你要去同一个地方，我就把你送上同一辆车。</p><p>但现实世界不是这样的。有时候，你需要让从专线进来的流量走昂贵的优质链路，而让来自公网的流量走廉价的拥塞链路；有时候，你需要根据 IP 包头的 TOS 字段来分流；有时候，你甚至需要根据防火墙打上的标记来决定路由。</p><p>这就是<strong>策略路由</strong>。它打破了「目的地决定一切」的规则，允许系统管理员定义「如果满足条件 A，就查表 B；如果满足条件 C，就查表 C」。</p><p>在这一节，我们重点讨论 IPv4 的策略路由实现（IPv6 的我们留到第 8 章再去折腾）。为了不让你的思维打架，我把策略路由里的条目称为<strong>规则</strong>，而把路由表里的条目称为<strong>路由</strong>。千万别搞混了：规则决定查哪张表，表决定往哪跳。</p><hr><h4 id="策略路由的管理" tabindex="-1">策略路由的管理 <a class="header-anchor" href="#策略路由的管理" aria-label="Permalink to &quot;策略路由的管理&quot;">​</a></h4><p>以前我们习惯用 <code>route</code> 命令来管理路由，但在策略路由这块，<code>route</code> 命令就显得力不从心了。你得靠 <code>iproute2</code> 包里的 <code>ip rule</code> 命令。这是一套完全不同的管理接口。</p><p>让我们来看看怎么玩转这些规则。</p><p><strong>添加规则</strong></p><p>假设你想让所有 TOS 字段为 <code>0x04</code> 的数据包去查表 <code>252</code>。你可以这样下命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tos</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0x04</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> table</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 252</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这一行命令背后发生了什么？</p><p>当你敲下回车，内核会调用 <code>net/core/fib_rules.c</code> 里的 <code>fib_nl_newrule()</code> 方法。它会在你的规则链里插入一条新规矩：以后凡是遇到 TOS 匹配 <code>0x04</code> 的包，别去查默认的 <code>main</code> 表了，去查 <code>table 252</code>。</p><p>光有规则还不够，表 <code>252</code> 里得有路。你可以这样往表 <code>252</code> 里塞路由：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> via</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.2.10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> table</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 252</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里的 <code>tos</code> 只是众多选择器中的一种。你可以匹配源地址、目的地址、入接口、防火墙标记（fwmark）等等。具体的参数表可以去查 <code>man 8 ip-rule</code>，或者翻到本章末尾的「快速参考」找 Table 6-1。</p><p><strong>删除规则</strong></p><p>不想玩了？删掉就行。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> del</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tos</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0x04</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> table</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 252</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个动作在内核里由 <code>fib_nl_delrule()</code> 接手，它会去规则链里把你之前加的那条给摘掉。</p><p><strong>查看规则</strong></p><p>想看看现在系统里都有哪些乱七八糟的规矩？</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或者</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这两个命令其实是一回事，它们最终都会调用内核里的 <code>fib_nl_dumprule()</code> 方法，把你定制的所有规则一股脑倒出来给你看。</p><p>搞清楚了怎么管理，我们就不得不扒开内核看看这东西到底是怎么造出来的。</p><hr><h4 id="内核实现细节" tabindex="-1">内核实现细节 <a class="header-anchor" href="#内核实现细节" aria-label="Permalink to &quot;内核实现细节&quot;">​</a></h4><p>这里有一点很容易让人晕头：源码树里有好几个叫 <code>fib_rules.c</code> 的文件。</p><ul><li><code>net/core/fib_rules.c</code>：这是真正的核心基础设施，它不特定于 IPv4 或 IPv6，是一个通用的框架。</li><li><code>net/ipv4/fib_rules.c</code>：这是 IPv4 对这个框架的实现。</li><li><code>net/ipv6/fib6_rules.c</code>：这是 IPv6 的实现。</li></ul><p>我们重点关注 IPv4 的实现。</p><p><strong>核心数据结构</strong></p><p>在 IPv4 的世界里，每一条规则最终都会被映射成一个 <code>fib4_rule</code> 结构体。定义在 <code>net/ipv4/fib_rules.c</code> 里：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> fib4_rule {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> fib_rule    common;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    u8            dst_len;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    u8            src_len;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    u8            tos;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __be32            src;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __be32            srcmask;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __be32            dst;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __be32            dstmask;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#ifdef</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> CONFIG_IP_ROUTE_CLASSID</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    u32            tclassid;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#endif</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>你可以看到，这里面不仅有源地址（<code>src</code>）、目的地址（<code>dst</code>），还有 TOS 字段。这些就是用来匹配数据包的「过滤器」。如果数据包的头部信息和这里面的字段对上了，这条规则就命中了。</p><p><strong>启动时的默认规则</strong></p><p>什么都没做的时候，你的系统里其实已经有三条铁律了。内核启动时，<code>fib_default_rules_init()</code> 方法会悄无声息地帮你创建三个默认策略：</p><ol><li><strong>Local 表 (RT_TABLE_LOCAL)</strong>：专门处理本地地址（比如 127.0.0.1）和广播地址。</li><li><strong>Main 表 (RT_TABLE_MAIN)</strong>：这就是我们平时用 <code>ip route</code> 看到的那张表，所有没打标记的常规流量都在这。</li><li><strong>Default 表 (RT_TABLE_DEFAULT)</strong>：这是最后的救命稻草，如果前面都没匹配上，就用这张表（通常是空的，或者丢给网关）。</li></ol><p><strong>查找流程：快路径与慢路径</strong></p><p>这是整个机制里最精妙的部分。当内核需要为一个数据包找路由时，它会调用 <code>fib_lookup()</code> 方法。</p><p>在 <code>include/net/ip_fib.h</code> 里，你会看到两个长得像但其实不同的 <code>fib_lookup()</code>。如果内核配置里没开 <code>CONFIG_IP_MULTIPLE_TABLES</code>（也就是没用策略路由），那就走那个简单的、查单表的逻辑。</p><p>但只要开启了策略路由，事情就变得有趣了。内核会面临两种情况：</p><ol><li><strong>快路径</strong>：变量 <code>net-&gt;ipv4.fib_has_custom_rules</code> 是 <code>false</code>。这意味着你从来没有动过默认规则，系统还是原装出厂设置。既然规则没变，那就不需要遍历规则链，直接按顺序查 Local → Main → Default 表。这省去了遍历规则的开销。</li><li><strong>慢路径</strong>：一旦你执行了 <code>ip rule add</code> 或者 <code>ip rule del</code>，<code>fib4_rule_configure()</code> 或 <code>fib4_rule_delete()</code> 就会把 <code>net-&gt;ipv4.fib_has_custom_rules</code> 设为 <code>true</code>。这时候，内核知道事情不简单了，它会调用 <code>_fib_lookup()</code>，进而进入 <code>fib_rules_lookup()</code>。</li></ol><p><code>fib_rules_lookup()</code> 做的事情很繁琐但很必要：它拿着数据包，在规则链表里从头走到尾，对每一条规则调用 <code>fib_rule_match()</code>。如果规则匹配上了，就去查该规则指定的那个路由表；如果没匹配上，就继续下一条。</p><p>这个逻辑虽然看起来笨重，但它是灵活性的代价。你想要自由，就得付出 CPU 周期。</p><hr><p>这里我们聊完了策略路由的架子。但有了策略路由，我们就能做更多花哨的事了。</p><p>下一节，我们要讨论一种更具体的「高级玩法」——<strong>多路径路由</strong>。也就是当路由表里告诉你「下一跳有两个，都可以走」的时候，内核该怎么选？是轮流？还是加权？这又是一个关乎平衡与性能的话题。</p>`,49)])])}const u=i(l,[["render",p]]);export{k as __pageData,u as default};
